from flask import Flask
from flask_restful import Api, Resource, reqparse

app = Flask(__name__)
api = Api(app)

# In-memory "database" for demonstration purposes
TODOS = {}
todo_id_counter = 0

# Argument parser for POST and PUT requests
parser = reqparse.RequestParser()
parser.add_argument('task', type=str, required=True, help='Task is required', location='json')

class TodoList(Resource):
    def get(self):
        """Returns all todos."""
        return TODOS

    def post(self):
        """Creates a new todo."""
        global todo_id_counter
        args = parser.parse_args()
        todo_id = f'todo{todo_id_counter}'
        TODOS[todo_id] = {'task': args['task']}
        todo_id_counter += 1
        return {todo_id: TODOS[todo_id]}, 201 # 201 Created

class Todo(Resource):
    def get(self, todo_id):
        """Returns a single todo by its ID."""
        if todo_id not in TODOS:
            return {'message': 'Todo not found'}, 404 # 404 Not Found
        return {todo_id: TODOS[todo_id]}

    def put(self, todo_id):
        """Updates an existing todo."""
        if todo_id not in TODOS:
            return {'message': 'Todo not found'}, 404
        args = parser.parse_args()
        TODOS[todo_id]['task'] = args['task']
        return {todo_id: TODOS[todo_id]}

    def delete(self, todo_id):
        """Deletes a todo."""
        if todo_id not in TODOS:
            return {'message': 'Todo not found'}, 404
        del TODOS[todo_id]
        return '', 204 # 204 No Content for successful deletion


# Add resources to the API with their respective routes
api.add_resource(TodoList, '/todos')
api.add_resource(Todo, '/todos/<string:todo_id>')

if __name__ == '__main__':
    app.run(debug=True)
